'use strict';

function slugStats(input) {
  if (typeof input !== 'string') {
    throw new TypeError('slugStats: input must be a string');
  }

  const matches = input.match(/[A-Za-z0-9]+/g);
  const tokens = matches === null ? [] : matches;
  const lowered = tokens.map((token) => token.toLowerCase());
  const unique = new Set(lowered);

  return {
    words: lowered.length,
    uniqueWords: unique.size,
    slug: lowered.join('-'),
  };
}

module.exports = { slugStats };
